SELECT MN_KEYNO , MVD_KEYNO, MVD_DATA, MVD_REGDT , (SELECT UI_NAME FROM u_userinfo WHERE UI_KEYNO = MVD.MVD_REGNM) MVD_REGNM , MVD_MODDT , (SELECT UI_NAME FROM u_userinfo WHERE UI_KEYNO = MVD.MVD_MODNM) MVD_MODNM , MN.MN_KEYNO, MN.MN_HOMEDIV_C, MN.MN_URL , SUBSTRING_INDEX(SUBSTRING_INDEX(MN.MN_URL,'/',2),'/',-1) MVD_TILES , MVD.MVD_EDITOR_TYPE , MAX(MVDH.MVH_VERSION) viewVersion FROM s_menu_view_data MVD LEFT JOIN s_menu_manager MN ON MVD.MVD_MN_KEYNO = MN.MN_KEYNO LEFT JOIN s_menu_view_data_history MVDH ON MVD.MVD_KEYNO = MVDH.MVH_MVD_KEYNO WHERE 1=1 AND MVD_DEL_YN = 'N' AND MN_KEYNO IS NOT NULL
AND MVD_KEYNO = #{MVD_KEYNO}
AND MVD_MN_HOMEDIV_C = #{MVD_MN_HOMEDIV_C}

SELECT MN_KEYNO , MVD_KEYNO, MVD_DATA, MVD_REGDT , (SELECT UI_NAME FROM u_userinfo WHERE UI_KEYNO = MVD.MVD_REGNM) MVD_REGNM , MVD_MODDT , (SELECT UI_NAME FROM u_userinfo WHERE UI_KEYNO = MVD.MVD_MODNM) MVD_MODNM , MN.MN_KEYNO, MN.MN_HOMEDIV_C, MN.MN_URL , SUBSTRING_INDEX(SUBSTRING_INDEX(MN.MN_URL,'/',2),'/',-1) MVD_TILES , MVD.MVD_EDITOR_TYPE FROM s_menu_view_data MVD LEFT JOIN s_menu_manager MN ON MVD.MVD_MN_KEYNO = MN.MN_KEYNO WHERE 1=1 AND MVD_DEL_YN = 'N' AND MN_KEYNO IS NOT NULL
AND MVD_KEYNO = #{MVD_KEYNO}
AND MVD_MN_HOMEDIV_C = #{MVD_MN_HOMEDIV_C}

SELECT 	CASE WHEN MVD_MODDT IS NULL THEN MVD_REGDT ELSE MVD_MODDT END REGDT
FROM 	s_menu_view_data
WHERE 	MVD_KEYNO 	= 	#{MVD_KEYNO}

SELECT MVD_KEYNO
FROM s_menu_view_data
WHERE MVD_MN_KEYNO = #{MN_KEYNO}

SELECT IFNULL(MAX(MVH_VERSION),0)
FROM s_menu_view_data_history
WHERE MVH_MVD_KEYNO = #{MVD_KEYNO}

